import json

with open(locals()['var_function-call-4679604093615905091'], 'r') as f:
    citations = json.load(f)

filenames = [c['title'] + ".txt" for c in citations]

# Regex for ACM source. 
# Using simple "ACM" might be too broad?
# But checking "Permission to make..." might be too strict if OCR is bad.
# "ACM" is a good tradeoff.
query = {
    "collection": "paper_docs",
    "filter": {
        "filename": {"$in": filenames},
        "text": {"$regex": "ACM"}
    },
    "projection": {"filename": 1}
}

print("__RESULT__:")
print(json.dumps(query))

