import json

with open(locals()['var_function-call-4679604093615905091'], 'r') as f:
    citations = json.load(f)

with open(locals()['var_function-call-18097155510583111270'], 'r') as f:
    batch1 = json.load(f)

with open(locals()['var_function-call-16661951326978437331'], 'r') as f:
    batch2 = json.load(f)

acm_docs = batch1 + batch2
acm_filenames = set(d['filename'] for d in acm_docs)

# Map title -> citation count
citation_map = {c['title']: c['citation_count'] for c in citations}

counts = []
for fname in acm_filenames:
    if fname.endswith('.txt'):
        title = fname[:-4]
        if title in citation_map:
            counts.append(int(citation_map[title]))

if len(counts) > 0:
    avg = sum(counts) / len(counts)
else:
    avg = 0

print("__RESULT__:")
print(json.dumps({
    "count": len(counts),
    "average": avg
}))

